<?php $payments=[]; try{$payments=db()->query('SELECT p.*, i.invoice_number, c.first_name, c.last_name FROM payments p LEFT JOIN invoices i ON i.id=p.invoice_id LEFT JOIN customers c ON c.id=p.customer_id ORDER BY p.id DESC LIMIT 200')->fetchAll();}catch(Throwable $e){} ?>
<div class="ao-page-head"><div><h2>Ödeme / İade Hareketleri</h2><p>Manuel ödeme, sanal POS dönüşleri, iadeler ve kredi işlemleri.</p></div><a class="ao-btn soft" href="<?= url('admin/accounting/invoices') ?>">Faturalar</a></div><div class="ao-card"><table class="ao-table"><thead><tr><th>Tarih</th><th>Fatura</th><th>Müşteri</th><th>Tip</th><th>Yöntem</th><th>Tutar</th><th>TX</th><th>Durum</th></tr></thead><tbody><?php foreach($payments as $p): ?><tr><td><?= e($p['created_at']) ?></td><td><?= e($p['invoice_number']??'-') ?></td><td><?= e(($p['first_name']??'').' '.($p['last_name']??'')) ?></td><td><?= e($p['type']) ?></td><td><?= e($p['method']) ?></td><td><?= number_format((float)$p['amount'],2,',','.') ?> <?= e($p['currency']) ?></td><td><?= e($p['transaction_id']) ?></td><td><?= e($p['status']) ?></td></tr><?php endforeach; if(!$payments): ?><tr><td colspan="8">Hareket yok.</td></tr><?php endif; ?></tbody></table></div>
